module matrix_mult (
    input [3:0] a11, a12, // First row of matrix A
    input [3:0] a21, a22, // Second row of matrix A
    input [3:0] b11, b12, // First row of matrix B
    input [3:0] b21, b22, // Second row of matrix B
    output [7:0] c11, c12, // First row of resulting matrix C
    output [7:0] c21, c22  // Second row of resulting matrix C
);
      wire _n01 = a11 * b11[0] ^ a12 * b21[0];
  wire _c01 = a11 * b11[0] & a12 * b21[0];
  wire _n02 = a11 * b11[1] ^ a12 * b21[1] ^ _c01;
  wire _c02 = (a11 * b11[1] & a12 * b21[1]) | (a11 * b11[1] & _c01) | (a12 * b21[1] & _c01);
  wire _n03 = a11 * b11[2] ^ a12 * b21[2] ^ _c02;
  wire _c03 = (a11 * b11[2] & a12 * b21[2]) | (a11 * b11[2] & _c02) | (a12 * b21[2] & _c02);
  wire _n04 = a11 * b11[3] ^ a12 * b21[3] ^ _c03;
  wire _c04 = (a11 * b11[3] & a12 * b21[3]) | (a11 * b11[3] & _c03) | (a12 * b21[3] & _c03);
  assign c11 = {_n01, _n02, _n03, _n04}; // C[0][0]
    assign c12 = a11 * b12 + a12 * b22; // C[0][1]
    assign c21 = a21 * b11 + a22 * b21; // C[1][0]
    assign c22 = a21 * b12 + a22 * b22; // C[1][1]
endmodule
